(function () {
  try {
    var DETAIL_PREFIX = 'https://www.ness-tech.co.il/careers/job/';
    var xhr = new XMLHttpRequest();
    xhr.open('GET', '/careers/api/Careers/GetAllItems', false);
    try { xhr.setRequestHeader('accept', 'application/json'); } catch (e) {}
    xhr.send();
    if (xhr.status !== 200) {
      var em = document.createElement('span');
      em.setAttribute('data-haide-setup-error', 'http_' + xhr.status);
      em.style.display = 'none';
      document.body.appendChild(em);
      return;
    }
    var data = JSON.parse(xhr.responseText);
    var list = (data && data.allOrderDetailsList) || [];
    var cards = document.querySelectorAll('.card-job-container');
    for (var i = 0; i < cards.length && i < list.length; i++) {
      var card = cards[i];
      if (card.querySelector('.haide-enrich')) continue;
      var d = list[i] || {};
      var domTitle = '';
      try {
        var liTitle = card.querySelectorAll('ul li')[1];
        if (liTitle) domTitle = (liTitle.textContent || '').replace(/\s+/g, ' ').trim();
      } catch (e) {}
      if (domTitle && d.title && domTitle.indexOf(d.title.replace(/\s+/g, ' ').trim()) === -1 &&
          d.title.replace(/\s+/g, ' ').trim().indexOf(domTitle) === -1) {
        var found = null;
        for (var k = 0; k < list.length; k++) {
          if (list[k] && list[k].title && (list[k].title.indexOf(domTitle) !== -1 || domTitle.indexOf(list[k].title) !== -1)) {
            found = list[k]; break;
          }
        }
        if (found) { d = found; } else { continue; }
      }
      var wrap = document.createElement('div');
      wrap.className = 'haide-enrich';
      wrap.style.display = 'none';
      function addSpan(cls, text) {
        var s = document.createElement('span');
        s.className = cls;
        s.textContent = text == null ? '' : String(text);
        wrap.appendChild(s);
      }
      function addLink(cls, href) {
        var a = document.createElement('a');
        a.className = cls;
        a.setAttribute('href', href);
        a.textContent = href;
        wrap.appendChild(a);
      }
      var descClean = (d.posDescription || '').replace(/<BR\s*\/?>/gi, '\n').replace(/&nbsp;/gi, ' ');
      addSpan('haide-title', d.title);
      addSpan('haide-location', d.posLocation);
      addSpan('haide-description', descClean);
      addSpan('haide-jobid', d.index);
      addSpan('haide-publish-date', d.lastUpdated);
      addSpan('haide-department', d.profName);
      addSpan('haide-subdept', d.subProfName);
      addSpan('haide-contact-name', d.rakazName);
      addSpan('haide-contact-email', d.rakazEmail);
      addSpan('haide-is-hot', d.isHot);
      if (d.index) addLink('haide-detail-url', DETAIL_PREFIX + d.index);
      card.appendChild(wrap);
    }
  } catch (e) {
    var em2 = document.createElement('span');
    em2.setAttribute('data-haide-setup-error', String(e).slice(0, 300));
    em2.style.display = 'none';
    document.body.appendChild(em2);
  }
})();

(function () {
  try {
    // Listing-only: each .job-container has onclick="jobline.openJob('A5.467')"
    // but no <a href>. We inject (a) a span carrying the clean uid for the
    // externalJobId field, and (b) an <a> with an absolute href to the
    // detail page so pageFlow `action: navigate` (which follows the first
    // <a> inside the item) can drive the detail-page navigation.
    var BASE = 'https://jobs.keshet-mediagroup.com';
    var items = document.querySelectorAll('.job-container');
    for (var i = 0; i < items.length; i++) {
      var it = items[i];
      if (it.querySelector('[data-extracted-jobid]')) continue;
      var onclick = it.getAttribute('onclick') || '';
      var m = onclick.match(/openJob\(\s*['"]([^'"]+)['"]\s*\)/);
      if (!m || !m[1]) continue;
      var uid = m[1];

      var idSpan = document.createElement('span');
      idSpan.setAttribute('data-extracted-jobid', uid);
      idSpan.style.display = 'none';
      idSpan.textContent = uid;
      it.appendChild(idSpan);

      var link = document.createElement('a');
      link.setAttribute('data-extracted-detailurl', '1');
      link.setAttribute('href', BASE + '/jobs/' + uid);
      link.style.display = 'none';
      link.textContent = 'detail';
      it.appendChild(link);
    }
  } catch (e) {
    try {
      var b = document.body;
      var es = document.createElement('span');
      es.setAttribute('data-setup-err', String(e).slice(0, 200));
      es.style.display = 'none';
      b.appendChild(es);
    } catch (_) {}
  }
})();

(function () {
  try {
    var sections = document.querySelectorAll('section.single_faq');
    sections.forEach(function (s) {
      var firstP = s.querySelector('.fqqcm p');
      if (!firstP) return;
      var txt = firstP.textContent || '';
      var m = txt.match(/מיקום המשרה:\s*([^\n\r]+?)(?:\s*תיאור|\s*מאפייני|\s*שעות|\s*$)/);
      if (m && m[1] && !s.querySelector('[data-extracted-location]')) {
        var span = document.createElement('span');
        span.setAttribute('data-extracted-location', '1');
        span.style.display = 'none';
        span.textContent = m[1].trim();
        s.appendChild(span);
      }
    });
  } catch (e) {}
})();

var w = window;
if (!w.angular) return;
var anchor = document.querySelector('.TableRowWrap') || document.body;
var s = w.angular.element(anchor).scope();
while (s && !s.Jobs) s = s.$parent;
if (!s || !Array.isArray(s.Jobs)) return;
var jobs = s.Jobs;
document.querySelectorAll('.TableRowWrap').forEach(function(n){ n.remove(); });
var host = document.body;
function esc(str){ var d=document.createElement('div'); d.textContent=str==null?'':String(str); return d.innerHTML; }
for (var i = 0; i < jobs.length; i++) {
  var j = jobs[i];
  var wrap = document.createElement('div');
  wrap.className = 'TableRowWrap';
  wrap.id = 'job_' + j.JobId;
  wrap.setAttribute('data-job-id', String(j.JobId));
  var apply = 'https://www.clalbit.co.il/careers/candidacy/?txtjobId=' + encodeURIComponent(j.JobId);
  wrap.innerHTML =
    '<span class="JobIdNumber" style="display:none">' + esc(j.JobId) + '</span>' +
    '<div class="TableCol">' + esc(j.JobTitle) + '</div>' +
    '<div class="TableCol">' + esc(j.Location) + '</div>' +
    '<div class="TableCol">' + esc(j.Extent) + '</div>' +
    '<div class="JobDetails">' + esc(j.JobDesc) + '</div>' +
    '<div class="WantedDesc">' + esc(j.Qualifications) + '</div>' +
    '<a class="SendBtn" href="' + apply + '">apply</a>';
  host.appendChild(wrap);
}
